import React, { useState, useEffect } from 'react';
import { groupsAPI, campaignsAPI, authAPI } from '../../utils/api';
import { useAuth } from '../../context/AuthContext';
import toast from 'react-hot-toast';

const ROLE_COLORS = {
  admin: '#a855f7', advertiser_manager: '#4f7dff', publisher_manager: '#06b6d4',
  advertiser: '#22c55e', publisher: '#f59e0b', am: '#4f7dff'
};

export default function CreateGroupModal({ onClose, onCreated }) {
  const { user } = useAuth();
  const [mode, setMode] = useState('campaign');
  const [campaigns, setCampaigns] = useState([]);
  const [users, setUsers] = useState([]);
  const [selectedCampaign, setSelectedCampaign] = useState('');
  const [campaignType, setCampaignType] = useState('agency'); // 'agency' | 'direct'
  const [groupName, setGroupName] = useState('');
  const [selectedMembers, setSelectedMembers] = useState([]);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    campaignsAPI.getAll().then(d => setCampaigns(d.campaigns || []));
    authAPI.getUsers().then(d => setUsers(d.users || []));
  }, []);

  const toggleMember = (id) => {
    setSelectedMembers(prev => prev.includes(id) ? prev.filter(m => m !== id) : [...prev, id]);
  };

  const handleCreate = async () => {
    setLoading(true);
    try {
      let group;
      if (mode === 'campaign') {
        if (!selectedCampaign) { toast.error('Select a campaign'); setLoading(false); return; }
        const data = await groupsAPI.createFromCampaign({
          campaign_id: parseInt(selectedCampaign),
          additional_members: selectedMembers,
          campaign_type: campaignType
        });
        group = data.group;
      } else {
        if (!groupName.trim()) { toast.error('Enter a group name'); setLoading(false); return; }
        const data = await groupsAPI.createCustom({
          group_name: groupName.trim(),
          member_ids: selectedMembers
        });
        group = data.group;
      }
      toast.success('Group created! 🚀');
      onCreated(group);
    } catch (err) {
      toast.error(err?.error || 'Failed to create group');
    } finally { setLoading(false); }
  };

  const selectedCamp = campaigns.find(c => c.id === parseInt(selectedCampaign));

  // What defaults will be added
  const defaultLabel = campaignType === 'direct'
    ? 'Akshat + Ipsita added automatically'
    : 'Atique + Anvisha added automatically';

  return (
    <div className="modal-overlay" onClick={e => e.target === e.currentTarget && onClose()}>
      <div className="modal" style={{ maxHeight: '90vh', overflowY: 'auto' }}>
        <div className="modal-header">
          <h2 className="modal-title">Create Chat Group</h2>
          <button className="btn-icon" onClick={onClose}>✕</button>
        </div>

        <div className="modal-body">
          {/* Mode tabs */}
          <div style={{ display: 'flex', gap: 8, marginBottom: 20 }}>
            <button className={`btn ${mode === 'campaign' ? 'btn-primary' : 'btn-secondary'}`}
              onClick={() => setMode('campaign')} style={{ flex: 1 }}>📊 From Campaign</button>
            {(user?.role === 'admin' || user?.role === 'advertiser_manager') && (
              <button className={`btn ${mode === 'custom' ? 'btn-primary' : 'btn-secondary'}`}
                onClick={() => setMode('custom')} style={{ flex: 1 }}>✏️ Custom Group</button>
            )}
          </div>

          {mode === 'campaign' && (
            <>
              {/* Campaign Type selector */}
              <div style={{ marginBottom: 16 }}>
                <label className="form-label">Campaign Type</label>
                <div style={{ display: 'flex', gap: 8 }}>
                  {['agency', 'direct'].map(t => (
                    <button key={t} onClick={() => setCampaignType(t)}
                      style={{
                        flex: 1, padding: '8px 0', borderRadius: 8, fontWeight: 600, fontSize: 13,
                        cursor: 'pointer', fontFamily: 'inherit', transition: 'all 0.15s',
                        background: campaignType === t ? (t === 'agency' ? '#4f7dff' : '#22c55e') : 'var(--bg-tertiary)',
                        color: campaignType === t ? 'white' : 'var(--text-secondary)',
                        border: `1px solid ${campaignType === t ? (t === 'agency' ? '#4f7dff' : '#22c55e') : 'var(--border)'}`,
                      }}>
                      {t === 'agency' ? '🏢 Agency' : '⚡ Direct'}
                    </button>
                  ))}
                </div>
                <div style={{ marginTop: 6, fontSize: 11, color: 'var(--text-muted)', padding: '5px 8px', background: 'var(--bg-active)', borderRadius: 6 }}>
                  {campaignType === 'direct'
                    ? '⚡ Direct: Akshat + Ipsita will be auto-added to this group'
                    : '🏢 Agency: Atique + Anvisha will be auto-added to this group'}
                </div>
              </div>

              <div className="form-group">
                <label className="form-label">Select Campaign</label>
                <select className="form-control" value={selectedCampaign} onChange={e => setSelectedCampaign(e.target.value)}>
                  <option value="">-- Choose a campaign --</option>
                  {campaigns.map(c => (
                    <option key={c.id} value={c.id}>{c.campaign_name} · {c.geo} · ${c.payout}</option>
                  ))}
                </select>

                {selectedCamp && (
                  <div style={{ marginTop: 10, background: 'var(--bg-tertiary)', border: '1px solid var(--border)', borderRadius: 8, padding: '10px 12px' }}>
                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 6, fontSize: 12 }}>
                      <div><span style={{ color: 'var(--text-muted)' }}>Package ID: </span><code style={{ color: 'var(--accent)' }}>{selectedCamp.package_id || '—'}</code></div>
                      <div><span style={{ color: 'var(--text-muted)' }}>Sub ID: </span><code style={{ color: 'var(--accent)' }}>{selectedCamp.sub_id || '—'}</code></div>
                      <div><span style={{ color: 'var(--text-muted)' }}>GEO: </span>{selectedCamp.geo}</div>
                      <div><span style={{ color: 'var(--text-muted)' }}>Payout: </span><strong>${selectedCamp.payout}</strong></div>
                      <div style={{ gridColumn: '1/-1' }}><span style={{ color: 'var(--text-muted)' }}>Event: </span>{selectedCamp.payable_event}</div>
                    </div>
                  </div>
                )}
                <p style={{ fontSize: 11, color: 'var(--text-muted)', marginTop: 8 }}>
                  Name: <code style={{ color: 'var(--accent)' }}>CampaignName_Adv_AM</code> · {defaultLabel} · Share Link task auto-created
                </p>
              </div>
            </>
          )}

          {mode === 'custom' && (
            <div className="form-group">
              <label className="form-label">Group Name</label>
              <input className="form-control" placeholder="e.g. BetFed Discussion" value={groupName} onChange={e => setGroupName(e.target.value)} />
            </div>
          )}

          {/* Member picker */}
          <div className="form-group">
            <label className="form-label">
              Add Additional Members
              {selectedMembers.length > 0 && (
                <span style={{ marginLeft: 6, background: '#4f7dff', color: 'white', borderRadius: 10, padding: '1px 7px', fontSize: 10, fontWeight: 700 }}>{selectedMembers.length}</span>
              )}
            </label>
            <div style={{ maxHeight: 200, overflowY: 'auto', border: '1px solid var(--border)', borderRadius: 8 }}>
              {users.filter(u => u.id !== user?.id).map(u => {
                const isDefault = ['atique','anvisha','akshat','ipsita'].includes(u.username);
                const isSelected = selectedMembers.includes(u.id);
                return (
                  <div key={u.id}
                    style={{ display: 'flex', alignItems: 'center', gap: 10, padding: '8px 12px', cursor: 'pointer', background: isSelected ? 'var(--accent-dim)' : 'transparent', borderBottom: '1px solid var(--border)', transition: 'background 0.1s' }}
                    onClick={() => toggleMember(u.id)}
                  >
                    <div style={{ width: 8, height: 8, borderRadius: '50%', background: isSelected ? 'var(--accent)' : 'var(--border)', flexShrink: 0 }} />
                    <div style={{ flex: 1 }}>
                      <div style={{ fontSize: 13, fontWeight: 500 }}>{u.full_name}</div>
                      <div style={{ fontSize: 11, color: ROLE_COLORS[u.role] || 'var(--text-muted)' }}>{u.role} · {u.email}</div>
                    </div>
                    {isDefault && <span style={{ fontSize: 10, color: 'var(--accent)', fontWeight: 600 }}>Auto</span>}
                  </div>
                );
              })}
            </div>
          </div>
        </div>

        <div className="modal-footer">
          <button className="btn btn-secondary" onClick={onClose}>Cancel</button>
          <button className="btn btn-primary" onClick={handleCreate} disabled={loading}>
            {loading ? '⏳ Creating...' : '✓ Create Group'}
          </button>
        </div>
      </div>
    </div>
  );
}
